export default function App({ onAdminChange }) {
  const [page, setPage] = useState("home"); const [isAdmin, setIsAdmin] = useState(false); const [showSettings, setShowSettings] = useState(false); const [showNotifications, setShowNotifications] = useState(false); const [showMore, setShowMore] = useState(false); const [classRegistrations, setClassRegistrations] = useState({}); const [reservationClass, setReservationClass] = useState(null); const [feedCelebrations, setFeedCelebrations] = useState({});
  const contentRef = useRef(null);
  useEffect(() => { window.scrollTo(0, 0); if (contentRef.current) contentRef.current.scrollTo(0, 0); }, [page]);
  const registerForClass = useCallback((cd) => { setClassRegistrations(prev => ({ ...prev, [cd.id]: (prev[cd.id] || 0) + 1 })); }, []);
  const openReservation = useCallback((cd) => { setReservationClass(cd); }, []);
  const celebrateFeed = useCallback((id) => { setFeedCelebrations(prev => ({ ...prev, [id]: (prev[id] || 0) + 1 })); }, []);

  const mainTabs = [{ id: "home", label: "Home", icon: Home }, { id: "classes", label: "Classes", icon: CalendarDays }, { id: "schedule", label: "Schedule", icon: Calendar }, { id: "practice", label: "Practice", icon: Flame }, { id: "more", label: "More", icon: Menu }];
  const moreItems = [{ id: "community", label: "Community", icon: Heart }, { id: "teachers", label: "Teachers", icon: Users }, { id: "events", label: "Events", icon: Star }, { id: "membership", label: "Pricing", icon: CreditCard }];
  const isMoreActive = moreItems.some(item => page === item.id);
  const adminTabs = [{ id: "admin-dashboard", label: "Dashboard", icon: LayoutDashboard }, { id: "admin-members", label: "Members", icon: Users }, { id: "admin-schedule", label: "Schedule", icon: Calendar }, { id: "admin-teachers", label: "Teachers", icon: UserCheck }, { id: "admin-events", label: "Events", icon: Star }, { id: "admin-pricing", label: "Pricing", icon: CreditCard }, { id: "admin-broadcast", label: "Broadcast", icon: Megaphone }];

  const renderPage = () => { switch (page) { case "home": return <HomePage />; case "classes": return <ClassesPage />; case "schedule": return <SchedulePage />; case "practice": return <PracticePage />; case "community": return <CommunityPage />; case "teachers": return <TeachersPage />; case "events": return <EventsPage />; case "membership": return <MembershipPage />; case "admin-dashboard": return <AdminDashboard />; case "admin-members": return <AdminMembersPage />; case "admin-schedule": return <AdminSchedulePage />; case "admin-teachers": return <AdminTeachersPage />; case "admin-events": return <AdminEventsPage />; case "admin-pricing": return <AdminPricingPage />; case "admin-broadcast": return <AdminBroadcastPage />; default: return <HomePage />; } };

  if (isAdmin) return (<AppContext.Provider value={{ page, setPage, classRegistrations, registerForClass, openReservation, feedCelebrations, celebrateFeed }}><div style={{ display: "flex", minHeight: "100vh", background: "#120e0a", fontFamily: "'DM Sans', system-ui, sans-serif", color: "#fff" }}><aside style={{ width: 240, background: "#161210", borderRight: "1px solid #3a2818", display: "flex", flexDirection: "column", position: "fixed", top: 0, bottom: 0 }}><div style={{ padding: "16px 14px", display: "flex", alignItems: "center", gap: 10, borderBottom: "1px solid #3a2818" }}><div style={{ width: 36, height: 36, borderRadius: 8, background: T.accent, display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden" }}><img src={STUDIO_IMAGES.logo} alt="SWEAT" style={{ width: 28, height: "auto" }} onError={e => { e.target.parentElement.textContent = "SW"; }} /></div><div><span style={{ fontFamily: "'Syne', sans-serif", fontSize: 16, color: "#fff", fontWeight: 700 }}>{STUDIO_CONFIG.name}</span><span style={{ display: "block", fontSize: 9, color: "#71717a", textTransform: "uppercase", letterSpacing: "0.15em" }}>Admin Panel</span></div></div><nav style={{ flex: 1, padding: "12px 8px", overflow: "auto" }}><p style={{ fontSize: 10, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.1em", color: "#71717a", padding: "0 10px", margin: "0 0 8px" }}>Management</p>{adminTabs.map(tab => { const active = page === tab.id; return (<button key={tab.id} onClick={() => setPage(tab.id)} style={{ display: "flex", alignItems: "center", gap: 10, width: "100%", padding: "10px 12px", borderRadius: 8, border: "none", background: active ? T.accent : "transparent", color: active ? "#fff" : "#a1a1aa", fontSize: 13, fontWeight: active ? 600 : 400, cursor: "pointer", marginBottom: 2, textAlign: "left" }}><tab.icon size={18} /><span>{tab.label}</span>{active && <ChevronRight size={14} style={{ marginLeft: "auto", opacity: 0.6 }} />}</button>); })}</nav><div style={{ borderTop: "1px solid #3a2818", padding: "10px 8px" }}><button onClick={() => { setIsAdmin(false); setPage("home"); if (onAdminChange) onAdminChange(false); }} style={{ display: "flex", alignItems: "center", gap: 10, width: "100%", padding: "10px 12px", borderRadius: 8, border: "none", background: "transparent", color: "#a1a1aa", fontSize: 13, cursor: "pointer", textAlign: "left" }}><LogOut size={18} /><span>Exit Admin</span></button></div></aside><main style={{ flex: 1, marginLeft: 240, padding: 24, overflow: "auto" }}>{renderPage()}</main></div></AppContext.Provider>);

  return (
    <AppContext.Provider value={{ page, setPage, classRegistrations, registerForClass, openReservation, feedCelebrations, celebrateFeed }}>
      <div ref={contentRef} style={{ maxWidth: 390, margin: "0 auto", minHeight: "100vh", background: T.bgDim, fontFamily: "'DM Sans', system-ui, sans-serif", position: "relative" }}>
        <header style={{ position: "sticky", top: 0, zIndex: 30, background: T.bg, color: "#fff", padding: "10px 14px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8, color: "#fff" }}>
            <div style={{ width: 38, height: 38, borderRadius: 10, background: T.accent, display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden" }}><img src={STUDIO_IMAGES.logo} alt="SWEAT" style={{ width: 30, height: "auto", objectFit: "contain" }} onError={e => { e.target.style.display = "none"; e.target.parentElement.innerHTML = '<span style="font-family:Syne,sans-serif;font-size:13px;color:#fff;font-weight:700">SW</span>'; }} /></div>
            <div style={{ display: "flex", flexDirection: "column" }}><span style={{ fontFamily: "'Syne', sans-serif", fontSize: 20, lineHeight: 1, fontWeight: 700 }}>{STUDIO_CONFIG.name}</span><span style={{ fontSize: 9, color: "#71717a", textTransform: "uppercase", letterSpacing: "0.15em" }}>{STUDIO_CONFIG.subtitle}</span></div>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 2 }}>
            <button onClick={() => { setIsAdmin(true); setPage("admin-dashboard"); if (onAdminChange) onAdminChange(true); }} style={{ padding: 8, borderRadius: 8, border: "none", background: "transparent", cursor: "pointer", color: T.accent }}><Shield size={20} /></button>
            <button onClick={() => setShowNotifications(true)} style={{ padding: 8, borderRadius: 8, border: "none", background: "transparent", cursor: "pointer", color: "#fff", position: "relative" }}><Bell size={20} /><span style={{ position: "absolute", top: 4, right: 4, width: 14, height: 14, borderRadius: "50%", background: T.accent, fontSize: 9, fontWeight: 700, display: "flex", alignItems: "center", justifyContent: "center", color: "#fff" }}>2</span></button>
            <button onClick={() => setShowSettings(true)} style={{ padding: 8, borderRadius: 8, border: "none", background: "transparent", cursor: "pointer", color: "#fff" }}><Settings size={20} /></button>
          </div>
        </header>
        <main style={{ paddingBottom: 80 }}>{renderPage()}</main>
        {showMore && (<div onClick={() => setShowMore(false)} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.5)", backdropFilter: "blur(4px)", zIndex: 40 }}><div onClick={e => e.stopPropagation()} style={{ position: "absolute", bottom: 68, left: 16, right: 16, maxWidth: 358, margin: "0 auto", background: T.bgCard, borderRadius: 16, padding: "14px 12px", boxShadow: "0 8px 32px rgba(0,0,0,.15)" }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "0 6px 8px" }}><span style={{ fontFamily: "'Syne', sans-serif", fontSize: 20, fontWeight: 700 }}>More</span><button onClick={() => setShowMore(false)} style={{ padding: 4, borderRadius: 6, border: "none", background: "transparent", cursor: "pointer" }}><X size={18} color={T.textMuted} /></button></div><div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>{moreItems.map(item => { const active = page === item.id; return (<button key={item.id} onClick={() => { setPage(item.id); setShowMore(false); }} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 6, padding: "14px 8px", borderRadius: 10, border: "none", cursor: "pointer", background: active ? T.accentGhost : T.bgDim, color: active ? T.accent : T.textMuted }}><item.icon size={22} /><span style={{ fontSize: 13, fontWeight: 600 }}>{item.label}</span></button>); })}</div></div></div>)}
        <nav style={{ position: "sticky", bottom: 0, left: 0, right: 0, zIndex: 30, background: T.bgCard, borderTop: `1px solid ${T.border}`, maxWidth: 390, margin: "0 auto" }}><div style={{ display: "flex", justifyContent: "space-around", padding: "6px 4px 10px" }}>{mainTabs.map(tab => { const active = tab.id === "more" ? (isMoreActive || showMore) : page === tab.id; if (tab.id === "more") return (<button key={tab.id} onClick={() => setShowMore(true)} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 2, padding: "6px 12px", borderRadius: 10, border: "none", background: "transparent", cursor: "pointer", color: active ? T.accent : T.textFaint }}><tab.icon size={20} strokeWidth={active ? 2.5 : 2} /><span style={{ fontSize: 10, fontWeight: active ? 700 : 500 }}>{tab.label}</span></button>); return (<button key={tab.id} onClick={() => setPage(tab.id)} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 2, padding: "6px 12px", borderRadius: 10, border: "none", background: "transparent", cursor: "pointer", color: active ? T.accent : T.textFaint }}><tab.icon size={20} strokeWidth={active ? 2.5 : 2} /><span style={{ fontSize: 10, fontWeight: active ? 700 : 500 }}>{tab.label}</span></button>); })}</div></nav>
        {showSettings && <SettingsModal onClose={() => setShowSettings(false)} />}
        {showNotifications && <NotificationsModal onClose={() => setShowNotifications(false)} />}
        {reservationClass && <ReservationModal classData={reservationClass} onConfirm={registerForClass} onClose={() => setReservationClass(null)} />}
      </div>
    </AppContext.Provider>
  );
}
